# Math utilities module

@static
class MathHelper:
    PI: float = 3.14159
    EULER: float = 2.71828

    @static
    def square(x: int) -> int:
        return x * x

    @static
    def cube(x: int) -> int:
        return x * x * x

    @static
    def is_even(n: int) -> bool:
        return n % 2 == 0

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    result: int = 1
    i: int = 2
    while i <= n:
        result = result * i
        i += 1
    return result

def clamp(value: int, min_val: int, max_val: int) -> int:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

