# Shapes module with classes using math_utils

from math_utils import MathHelper, factorial, clamp

@abstract
class Shape:
    name: str

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    def describe(self) -> str:
        return "Shape: " + self.name

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height
        self.name = "Rectangle"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        self.radius = radius
        self.name = "Circle"

    @override
    def area(self) -> float:
        return MathHelper.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * MathHelper.PI * self.radius

    def diameter(self) -> float:
        return 2.0 * self.radius

def scale_dimension(value: float, factor: int) -> float:
    # Clamp the factor using math_utils
    clamped: int = clamp(factor, 1, 5)
    return value * float(clamped)

def create_default_rectangle() -> Rectangle:
    return Rectangle(10.0, 5.0)
